// Fold icmp eq/ne V, clamp(V, Lo, Hi) to a range check.
// clamp(V, Lo, Hi) is smin(smax(V, Lo), Hi) for signed or umin(umax(V, Lo), Hi)
// for unsigned.
// V == clamp(V, Lo, Hi) iff Lo <= V <= Hi
//   which is equivalent to 0 <= (V - Lo) <= (Hi - Lo)
//   which is (V - Lo) ult (Hi - Lo + 1) for unsigned comparison.
static Instruction *foldICmpWithClamp(ICmpInst &I, InstCombiner::BuilderTy &Builder) {
  if (!I.isEquality())
    return nullptr;

  Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1);
  ICmpInst::Predicate Pred = I.getPredicate();

  // Try both operand orders
  MinMaxIntrinsic *Outer = dyn_cast<MinMaxIntrinsic>(Op0);
  Value *V = Op1;
  if (!Outer) {
    Outer = dyn_cast<MinMaxIntrinsic>(Op1);
    V = Op0;
  }
  if (!Outer)
    return nullptr;

  // Check for clamp pattern: Outer = MinMax(Inner, Hi), Inner = MinMax(V, Lo)
  // with matching signedness
  auto *Inner = dyn_cast<MinMaxIntrinsic>(Outer->getArgOperand(0));
  if (!Inner)
    return nullptr;
  if (Outer->isSigned() != Inner->isSigned())
    return nullptr;

  // Check that Inner's first operand is V (the value being compared)
  if (Inner->getArgOperand(0) != V)
    return nullptr;

  // Check that V is not used elsewhere in the clamp
  if (Inner->getArgOperand(1) == V || Outer->getArgOperand(1) == V)
    return nullptr;

  // Get the constants Lo and Hi
  const APInt *Lo, *Hi;
  if (!match(Inner->getArgOperand(1), m_APInt(Lo)))
    return nullptr;
  if (!match(Outer->getArgOperand(1), m_APInt(Hi)))
    return nullptr;

  // Check that Lo <= Hi (valid clamp range)
  if (Outer->isSigned()) {
    if (Lo->sgt(*Hi))
      return nullptr;
  } else {
    if (Lo->ugt(*Hi))
      return nullptr;
  }

  // Compute the range check: (V - Lo) ult (Hi - Lo + 1)
  Type *Ty = V->getType();
  Constant *LoConst = ConstantInt::get(Ty, *Lo);
  Constant *RangeConst = ConstantInt::get(Ty, *Hi - *Lo + 1);

  Value *Sub = Builder.CreateSub(V, LoConst, "clamp.offset");
  Instruction *NewCmp = new ICmpInst(ICmpInst::ICMP_ULT, Sub, RangeConst);

  if (Pred == ICmpInst::ICMP_NE) {
    // For NE, we want the negation: (V - Lo) uge (Hi - Lo + 1)
    cast<ICmpInst>(NewCmp)->setPredicate(ICmpInst::ICMP_UGE);
  }

  return NewCmp;
